INSERT INTO attractions (
  id, city_id, name, chinese_name, category, cover_image_path, summary, introduction,
  priority, ticket_price, recommended_duration, opening_hours, closed_days,
  requires_advance_booking, metro_access, western_visitor_tips, nearby_places,
  address_en, address_zh, audio_guide_count, iap_product_id, display_order, is_published
) VALUES (
  'chengdu_wuhou_shrine', 'chengdu', 'Wuhou Shrine', '武侯祠',
  'temple', NULL, 'China''s only shrine jointly honoring a ruler and his minister — the holy ground of Three Kingdoms culture.', 'The Wuhou Shrine Museum is China''s only shrine jointly dedicated to a ruler and his minister, honoring the heroes of the Shu Han kingdom — Liu Bei, Zhuge Liang, Guan Yu and Zhang Fei. Founded in 223 AD and standing for over 1,780 years, it is the most globally influential museum of Three Kingdoms culture, known as the “Sacred Ground of the Three Kingdoms.” The 153,300 m² grounds bring together historical relics, classical gardens and the lively Jinli folk-culture street.',
  'P0', '¥50 (~$7)', '2–3 hours',
  '9:00 AM – 6:00 PM (last entry 5:00 PM)', NULL,
  FALSE, 'Line 3 · Gaoshengqiao',
  '["Admission is ¥50 per person; students and visitors over 60 pay half price (¥25).","Open 9 AM–6 PM with last entry at 5 PM; come on a weekday right at opening to beat the crowds.","Walk the Red Wall Passage by Huiling for the shrine’s most photogenic bamboo-shaded corridor.","Exit south into Jinli Ancient Street for Sichuan street food and Three Kingdoms souvenirs."]'::jsonb, '[{"name":"Jinli Ancient Street","distance":"Adjacent (south exit)"},{"name":"Sichuan Provincial Library","distance":"10 min walk"}]'::jsonb,
  '231 Wuhou Ci Street, Wuhou District, Chengdu', '四川省成都市武侯区武侯祠大街231号',
  10, NULL, 0, TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id, name = EXCLUDED.name, chinese_name = EXCLUDED.chinese_name,
